const e=JSON.parse('{"key":"v-fda31dd8","path":"/tech/java/%E5%A6%82%E4%BD%95%E4%BC%98%E9%9B%85%E5%9C%B0%E5%81%9C%E6%AD%A2Thread.html","title":"如何优雅地停止Thread","lang":"zh-CN","frontmatter":{"date":"2019-07-08T23:18:00.000Z","category":["Java"],"tag":["线程"],"description":"如何优雅地停止Thread 作者：大闲人柴毛毛 interrupted()是Java提供的一种中断机制，要把中断搞清楚，还是得先系统性了解下什么是中断机制。 什么是中断？ 在Java中没有办法立即停止一条线程，然而停止线程却显得尤为重要，如取消一个耗时操作。因此，Java提供了一种用于停止线程的机制——中断。 中断只是一种协作机制，Java没有给中断增加任何语法，中断的过程完全需要程序员自己实现。若要中断一个线程，你需要手动调用该线程的interrupted方法，该方法也仅仅是将线程对象的中断标识设成true；接着你需要自己写代码不断地检测当前线程的标识位；如果为true，表示别的线程要求这条线程中断，此时究竟该做什么需要你自己写代码实现。 每个线程对象中都有一个标识，用于表示线程是否被中断；该标识位为true表示中断，为false表示未中断； 通过调用线程对象的interrupt方法将该线程的标识位设为true；可以在别的线程中调用，也可以在自己的线程中调用。","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/java/%E5%A6%82%E4%BD%95%E4%BC%98%E9%9B%85%E5%9C%B0%E5%81%9C%E6%AD%A2Thread.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"如何优雅地停止Thread"}],["meta",{"property":"og:description","content":"如何优雅地停止Thread 作者：大闲人柴毛毛 interrupted()是Java提供的一种中断机制，要把中断搞清楚，还是得先系统性了解下什么是中断机制。 什么是中断？ 在Java中没有办法立即停止一条线程，然而停止线程却显得尤为重要，如取消一个耗时操作。因此，Java提供了一种用于停止线程的机制——中断。 中断只是一种协作机制，Java没有给中断增加任何语法，中断的过程完全需要程序员自己实现。若要中断一个线程，你需要手动调用该线程的interrupted方法，该方法也仅仅是将线程对象的中断标识设成true；接着你需要自己写代码不断地检测当前线程的标识位；如果为true，表示别的线程要求这条线程中断，此时究竟该做什么需要你自己写代码实现。 每个线程对象中都有一个标识，用于表示线程是否被中断；该标识位为true表示中断，为false表示未中断； 通过调用线程对象的interrupt方法将该线程的标识位设为true；可以在别的线程中调用，也可以在自己的线程中调用。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-22T17:33:14.000Z"}],["meta",{"property":"article:tag","content":"线程"}],["meta",{"property":"article:published_time","content":"2019-07-08T23:18:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-22T17:33:14.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"如何优雅地停止Thread\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2019-07-08T23:18:00.000Z\\",\\"dateModified\\":\\"2023-03-22T17:33:14.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"什么是中断？","slug":"什么是中断","link":"#什么是中断","children":[]},{"level":2,"title":"中断的相关方法","slug":"中断的相关方法","link":"#中断的相关方法","children":[]},{"level":2,"title":"如何使用中断？","slug":"如何使用中断","link":"#如何使用中断","children":[]},{"level":2,"title":"如何安全地停止线程？","slug":"如何安全地停止线程","link":"#如何安全地停止线程","children":[{"level":3,"title":"1.循环标记变量","slug":"_1-循环标记变量","link":"#_1-循环标记变量","children":[]},{"level":3,"title":"2.循环中断状态","slug":"_2-循环中断状态","link":"#_2-循环中断状态","children":[]}]},{"level":2,"title":"如何处理中断？","slug":"如何处理中断","link":"#如何处理中断","children":[]}],"git":{"createdTime":1679384580000,"updatedTime":1679506394000,"contributors":[{"name":"dhb","email":"xx158@qq.com","commits":1},{"name":"donghaibin","email":"xx158@qq.com","commits":1}]},"readingTime":{"minutes":5.15,"words":1544},"filePathRelative":"tech/java/如何优雅地停止Thread.md","localizedDate":"2019年7月8日","excerpt":"<h1> 如何优雅地停止Thread</h1>\\n<p>作者：大闲人柴毛毛</p>\\n<p>interrupted()是Java提供的一种中断机制，要把中断搞清楚，还是得先系统性了解下什么是中断机制。</p>\\n<h2> <strong>什么是中断？</strong></h2>\\n<p>在Java中没有办法立即停止一条线程，然而停止线程却显得尤为重要，如取消一个耗时操作。因此，Java提供了一种用于停止线程的机制——中断。</p>\\n<ul>\\n<li>中断只是一种协作机制，Java没有给中断增加任何语法，中断的过程完全需要程序员自己实现。若要中断一个线程，你需要手动调用该线程的interrupted方法，该方法也仅仅是将线程对象的中断标识设成true；接着你需要自己写代码不断地检测当前线程的标识位；如果为true，表示别的线程要求这条线程中断，此时究竟该做什么需要你自己写代码实现。</li>\\n<li>每个线程对象中都有一个标识，用于表示线程是否被中断；该标识位为true表示中断，为false表示未中断；</li>\\n<li>通过调用线程对象的interrupt方法将该线程的标识位设为true；可以在别的线程中调用，也可以在自己的线程中调用。</li>\\n</ul>","autoDesc":true}');export{e as data};
